20	if (globalStore.habits.length === 0) {
21	  const seedHabits = [
22	    { domainId: "健身", title: "晨跑 30 分钟", description: "公园慢跑，心率保持在130-150", unit: "分钟", targetValue: 30, frequency: "daily" },
