27	    { domainId: "学习", title: "学习新技能 45 分钟", description: "在线课程或实践项目", unit: "分钟", targetValue: 45, frequency: "daily" },
28	    { domainId: "商业思维", title: "商业案例分析", description: "每天分析一个商业案例或新闻", unit: "个", targetValue: 1, frequency: "daily" },
