32	  seedHabits.forEach((h) => {
33	    globalStore.habits.push({ id: crypto.randomUUID(), userId: "demo", ...h, isActive: true, reminderTime: null, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
