1	import { NextRequest, NextResponse } from "next/server";
2	import { store } from "@/lib/store";
3	
4	export async function GET(req: NextRequest) {
5	  const searchParams = req.nextUrl.searchParams;
6	  const date = searchParams.get("date");
7	
8	  const habits = store.habits.map((h) => {
9	    const log = date
10	      ? store.habitLogs.find((l: any) => l.habitId === h.id && l.date === date)
11	      : undefined;
12	    return { ...h, logs: log ? [log] : [] };
13	  });
14	
15	  return NextResponse.json(habits);
16	}
17	
18	export async function POST(req: NextRequest) {
19	  const body = await req.json();
20	  const habit = {
21	    id: crypto.randomUUID(),
22	    userId: "demo",
23	    ...body,
24	    isActive: true,
25	    createdAt: new Date().toISOString(),
26	    updatedAt: new Date().toISOString(),
27	  };
28	  store.habits.push(habit);
29	  return NextResponse.json(habit);
30	}
31	
32	export async function PUT(req: NextRequest) {
33	  const { id, ...updates } = await req.json();
34	  const idx = store.habits.findIndex((h: any) => h.id === id);
35	  if (idx === -1) return NextResponse.json({ error: "Not found" }, { status: 404 });
36	  store.habits[idx] = { ...store.habits[idx], ...updates, updatedAt: new Date().toISOString() };
37	  return NextResponse.json(store.habits[idx]);
38	}
39	
40	export async function DELETE(req: NextRequest) {
41	  const { id } = await req.json();
42	  store.habits = store.habits.filter((h: any) => h.id !== id);
43	  store.habitLogs = store.habitLogs.filter((l: any) => l.habitId !== id);
44	  return NextResponse.json({ ok: true });
45	}
