1	const DEEPSEEK_BASE = "https://api.deepseek.com/chat/completions";
2	const API_KEY = process.env.CLAUDE_API_KEY || "";
3	
4	export async function getAIRecommendation(prompt: string): Promise<string> {
5	  if (!API_KEY) throw new Error("API key not configured");
6	
7	  const res = await fetch(DEEPSEEK_BASE, {
8	    method: "POST",
9	    headers: {
10	      "Content-Type": "application/json",
11	      "Authorization": `Bearer ${API_KEY}`,
12	    },
13	    body: JSON.stringify({
14	      model: "deepseek-chat",
15	      messages: [
16	        { role: "system", content: "你是一位专业的个人成长教练。回复简洁有力，风格如帝王侍读。每段不超过3句话。" },
17	        { role: "user", content: prompt },
18	      ],
19	      max_tokens: 1024,
20	      temperature: 0.7,
21	    }),
22	  });
23	
24	  if (!res.ok) {
25	    const errText = await res.text().catch(() => "");
26	    throw new Error(`DeepSeek API error ${res.status}: ${errText}`);
27	  }
28	
29	  const data = await res.json();
30	  return data.choices?.[0]?.message?.content || "";
31	}
