3	export async function apiFetch(path: string, options?: RequestInit) {
4	  const url = `${API_BASE}${path}`;
5	  const res = await fetch(url, {
6	    ...options,
7	    headers: {
8	      "Content-Type": "application/json",
9	      ...options?.headers,
